import { StickyNav } from "@/components/organisms/StickyNav";
import { Footer } from "@/components/organisms/Footer";
import { DocSection } from "@/components/molecules/DocSection";
import { Container } from "@/components/atoms/Container";
import { FadeIn } from "@/components/atoms/FadeIn";
import { getMdxContent } from "@/lib/mdx";
import { MDXRemote } from "next-mdx-remote/rsc";
import { mdxComponents } from "@/components/mdx-components";

export default function Home() {
  const rootContent = getMdxContent("");
  const designJourney = getMdxContent("design-journey");
  const caseStudies = getMdxContent("case-studies");

  // Helper to find specific section
  const getSection = (id: string) => rootContent.find(c => c.slug === id);
  
  const intro = getSection("introduction");
  const about = getSection("about");
  const timeline = getSection("timeline");
  const skills = getSection("skills");
  const docs = getSection("docs");
  const contact = getSection("contact");

  return (
    <>
      <StickyNav />
      <main className="flex-1 mt-24">
        {intro && (
          <section id="introduction" className="py-20 md:py-32">
            <Container>
              <FadeIn>
                <MDXRemote source={intro.content} components={mdxComponents} />
              </FadeIn>
            </Container>
          </section>
        )}

        {about && (
          <DocSection id="about" title={about.frontmatter.title}>
            <MDXRemote source={about.content} components={mdxComponents} />
          </DocSection>
        )}

        {timeline && (
          <DocSection id="timeline" title={timeline.frontmatter.title}>
            <MDXRemote source={timeline.content} components={mdxComponents} />
          </DocSection>
        )}

        <DocSection id="journey" title="Design Journey">
          <div className="space-y-16">
            {designJourney.map((chapter) => (
              <div key={chapter.slug} className="relative">
                <h3 className="text-sm font-semibold tracking-wider uppercase text-[var(--accent)] mb-2">
                  {chapter.frontmatter.title}
                </h3>
                <h4 className="text-2xl font-serif text-gray-900 mb-6">
                  {chapter.frontmatter.company}
                </h4>
                <MDXRemote source={chapter.content} components={mdxComponents} />
              </div>
            ))}
          </div>
        </DocSection>

        {caseStudies.length > 0 && (
          <DocSection id="case-studies" title="Selected Work">
            <div className="space-y-24">
              {caseStudies.map((study) => (
                <article key={study.slug} className="border border-[var(--neutral-light)] rounded-xl p-6 md:p-10 bg-white shadow-sm">
                  <h3 className="text-sm font-semibold tracking-wider uppercase text-[var(--accent)] mb-2">
                    Case Study
                  </h3>
                  <h4 className="text-3xl font-serif text-gray-900 mb-8 pb-4 border-b border-[var(--neutral-light)]">
                    {study.frontmatter.title}
                  </h4>
                  <MDXRemote source={study.content} components={mdxComponents} />
                </article>
              ))}
            </div>
          </DocSection>
        )}

        {skills && (
          <DocSection id="skills" title={skills.frontmatter.title}>
            <MDXRemote source={skills.content} components={mdxComponents} />
          </DocSection>
        )}

        {docs && (
          <DocSection id="docs" title={docs.frontmatter.title}>
            <MDXRemote source={docs.content} components={mdxComponents} />
          </DocSection>
        )}

        {contact && (
          <DocSection id="contact" title={contact.frontmatter.title}>
            <MDXRemote source={contact.content} components={mdxComponents} />
          </DocSection>
        )}
      </main>
      <Footer />
    </>
  );
}
